#include <bits/stdc++.h>
using namespace std;
const int N=20,M=1<<16;
int w1,n,t[M],w[M],dp[M];
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>w1>>n;
    for(int i=0;i<n;i++)
    {
        cin>>t[1<<i]>>w[1<<i];
    }
    for(int i=2;i<(1<<n);i++)
    {
        t[i]=max(t[i-(i&(-i))],t[i&(-i)]),w[i]=w[i-(i&(-i))]+w[i&(-i)];
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;
    for(int i=1;i<(1<<n);i++)
    {
        for(int j=i;j>0;j=i&(j-1))
        {
            if(w[j]<=w1)
            {
                dp[i]=min(dp[i],dp[i^j]+t[j]);
            }
        }
    }
    cout<<dp[(1<<n)-1];
    return 0;
}
